import {
  Component,
  computed,
  inject,
  signal,
  TemplateRef,
  ViewChild,
  OnInit,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { catchError, of } from 'rxjs';
import { ConfirmationService } from 'primeng/api';
import { ConfirmPopup } from 'primeng/confirmpopup';

import { AppStoreService } from '../../services/app-store.service';
import { AppDefinitionListItem, AppInvite } from '../../models/app-store.models';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { AppInviteService } from '../../services/app-invite.service';
import { AppInstallationService, AppInstallation } from '../../services/app-installation.service';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { TooltipModule } from 'primeng/tooltip';
import { DrawerModule } from 'primeng/drawer';
import { MessageModule } from 'primeng/message';
import { GridComponent } from '../../../../shared/components/grid/grid.component';
import { GridColumn } from '../../../../shared/models/grid.model';
import { AppStatusBadgeComponent } from '../../components/app-status-badge/app-status-badge.component';
import { AppInviteStatusBadgeComponent } from '../../components/app-invite-status-badge/app-invite-status-badge.component';
import { ImgFallbackDirective } from '../../../../shared/directives';

@Component({
  selector: 'app-creator-dashboard',
  imports: [
    CommonModule,
    RouterModule,
    ButtonModule,
    CardModule,
    ProgressSpinnerModule,
    TooltipModule,
    DrawerModule,
    ConfirmPopup,
    MessageModule,
    GridComponent,
    AppStatusBadgeComponent,
    AppInviteStatusBadgeComponent,
    ImgFallbackDirective,
  ],
  providers: [ConfirmationService],
  templateUrl: './app-creator-dashboard.component.html',
  styleUrls: ['./app-creator-dashboard.component.scss'],
})
export class AppCreatorDashboardComponent implements OnInit {
  private readonly appStoreService = inject(AppStoreService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly appInviteService = inject(AppInviteService);
  private readonly appInstallationService = inject(AppInstallationService);
  private readonly confirmationService = inject(ConfirmationService);
  private readonly router = inject(Router);

  @ViewChild('appIconTemplate', { static: true })
  appIconTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;
  @ViewChild('statusTemplate', { static: true })
  statusTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;
  @ViewChild('inReviewTemplate', { static: true })
  inReviewTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;
  @ViewChild('actionsTemplate', { static: true })
  actionsTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;
  @ViewChild('invitesActionTemplate', { static: true })
  invitesActionTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;
  @ViewChild('installersActionTemplate', { static: true })
  installersActionTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;
  @ViewChild('clientIdTemplate', { static: true })
  clientIdTemplate!: TemplateRef<{ $implicit: AppDefinitionListItem }>;

  // State Signals
  readonly isLoading = signal(true);
  readonly error = signal<string | null>(null);
  readonly apps = signal<AppDefinitionListItem[]>([]);
  readonly reviewComments = signal<Map<string, string>>(new Map());
  readonly processingAppId = signal<string | null>(null);
  readonly actionError = signal<string | null>(null);

  // Invite panel state
  readonly invitePanelApp = signal<AppDefinitionListItem | null>(null);
  readonly invites = signal<AppInvite[]>([]);
  readonly invitesLoading = signal(false);
  readonly isCreatingInvite = signal(false);

  // Installer panel state
  readonly installerPanelApp = signal<AppDefinitionListItem | null>(null);
  readonly installers = signal<AppInstallation[]>([]);
  readonly installersLoading = signal(false);

  readonly attentionApps = computed(() =>
    this.apps().filter(
      (app) => app.version.pendingVersionStatus === 'changesRequested',
    ),
  );

  readonly columns = signal<GridColumn<AppDefinitionListItem>[]>([]);

  constructor() {
    this.loadApps();
  }

  ngOnInit(): void {
    this.setupColumns();
  }

  private setupColumns(): void {
    this.columns.set([
      {
        field: 'name',
        header: 'App',
        sortable: true,
        cellTemplate: this.appIconTemplate,
      },
      {
        field: 'status',
        header: 'Status',
        sortable: true,
        cellTemplate: this.statusTemplate,
      },
      {
        field: 'version.activeVersionNumber',
        header: 'Live Version',
        sortable: false,
        valueGetter: (app) => app.version.activeVersionNumber ?? '—',
      },
      {
        field: 'version.pendingVersionNumber',
        header: 'In Review',
        sortable: false,
        cellTemplate: this.inReviewTemplate,
      },
      {
        field: 'stats.installCount',
        header: 'Installs',
        sortable: true,
        transform: 'font-mono',
        valueGetter: (app) => app.stats.installCount,
      },
      {
        field: 'stats.averageRating',
        header: 'Rating',
        sortable: true,
        valueGetter: (app) => app.stats.averageRating,
      },
      {
        field: 'updatedDate',
        header: 'Last Updated',
        sortable: true,
        valueGetter: (app) => new Date(app.updatedDate).toLocaleDateString(),
      },
      {
        field: 'actions',
        header: 'Actions',
        cellTemplate: this.actionsTemplate,
      },
      {
        field: 'version.active.clientId',
        header: 'Client ID',
        cellTemplate: this.clientIdTemplate,
      },
      {
        field: 'invites',
        header: 'Invites',
        cellTemplate: this.invitesActionTemplate,
      },
      {
        field: 'installers',
        header: 'Installers',
        cellTemplate: this.installersActionTemplate,
      },
    ]);
  }

  private loadApps(): void {
    this.isLoading.set(true);
    this.error.set(null);

    this.appStoreService
      .getMyApps({
        owner: this.clientDataService.getSelectedClient()?.id ?? '',
      })
      .pipe(
        catchError(() => {
          this.error.set('Unable to load your apps. Please try again.');
          return of([] as AppDefinitionListItem[]);
        }),
      )
      .subscribe((apps) => {
        this.apps.set(apps);
        this.isLoading.set(false);
        this.loadReviewComments(apps);
      });
  }

  private loadReviewComments(apps: AppDefinitionListItem[]): void {
    const attentionApps = apps.filter(
      (app) => app.version.pendingVersionStatus === 'changesRequested',
    );

    attentionApps.forEach((app) => {
      this.appStoreService
        .getSubmissionReviews(app.id)
        .pipe(catchError(() => of([])))
        .subscribe((reviews) => {
          if (reviews.length > 0) {
            this.reviewComments.update((map) => {
              const updated = new Map(map);
              updated.set(app.id, reviews[0].comments);
              return updated;
            });
          }
        });
    });
  }

  isEditDisabled(app: AppDefinitionListItem): boolean {
    return app.version.pendingVersionStatus === 'pendingReview';
  }

  confirmArchiveApp(event: Event, app: AppDefinitionListItem): void {
    this.confirmationService.confirm({
      target: event.target as EventTarget,
      message: `Archive <strong>${app.name}</strong>? It will be removed from the marketplace. You can re-publish it later.`,
      icon: 'pi pi-archive',
      acceptLabel: 'Archive',
      rejectLabel: 'Cancel',
      accept: () => this.archiveApp(app),
    });
  }

  private archiveApp(app: AppDefinitionListItem): void {
    this.actionError.set(null);
    this.processingAppId.set(app.id);
    this.appStoreService
      .archiveApp(app.id)
      .pipe(
        catchError(() => {
          this.actionError.set(`Failed to archive "${app.name}". Please try again.`);
          return of(null);
        }),
      )
      .subscribe((updated) => {
        if (updated) {
          this.apps.update((list) =>
            list.map((a) => (a.id === updated.id ? { ...a, state: updated.state } : a)),
          );
        }
        this.processingAppId.set(null);
      });
  }

  confirmDeleteApp(event: Event, app: AppDefinitionListItem): void {
    this.confirmationService.confirm({
      target: event.target as EventTarget,
      message: `Permanently delete <strong>${app.name}</strong>? This cannot be undone.`,
      icon: 'pi pi-exclamation-triangle',
      acceptLabel: 'Delete',
      acceptButtonStyleClass: 'p-button-danger',
      rejectLabel: 'Cancel',
      accept: () => this.deleteApp(app),
    });
  }

  private deleteApp(app: AppDefinitionListItem): void {
    this.actionError.set(null);
    this.processingAppId.set(app.id);
    let failed = false;
    this.appStoreService
      .deleteApp(app.id)
      .pipe(
        catchError((err) => {
          failed = true;
          const message =
            err?.status === 400
              ? `"${app.name}" has active installations and cannot be deleted. Archive it first to remove it from the marketplace.`
              : `Failed to delete "${app.name}". Please try again.`;
          this.actionError.set(message);
          return of(undefined);
        }),
      )
      .subscribe(() => {
        if (!failed) {
          this.apps.update((list) => list.filter((a) => a.id !== app.id));
        }
        this.processingAppId.set(null);
      });
  }

  reload(): void {
    this.loadApps();
  }

  editApp(app: AppDefinitionListItem): void {
    this.router
      .navigate(['/app-store/editor'], {
        queryParams: { appId: app.id },
        state: { appToEdit: app },
      })
      .catch(() => {});
  }

  openInvitePanel(app: AppDefinitionListItem): void {
    this.invitePanelApp.set(app);
    this.invitesLoading.set(true);
    this.invites.set([]);
    this.appInviteService
      .getInvites(app.id)
      .pipe(catchError(() => of([] as AppInvite[])))
      .subscribe((invites) => {
        this.invites.set(invites);
        this.invitesLoading.set(false);
      });
  }

  closeInvitePanel(): void {
    this.invitePanelApp.set(null);
    this.invites.set([]);
  }

  openInstallerPanel(app: AppDefinitionListItem): void {
    this.installerPanelApp.set(app);
    this.installersLoading.set(true);
    this.installers.set([]);
    this.appInstallationService
      .getAppInstallations(app.id)
      .pipe(catchError(() => of([] as AppInstallation[])))
      .subscribe((installers) => {
        this.installers.set(installers);
        this.installersLoading.set(false);
      });
  }

  closeInstallerPanel(): void {
    this.installerPanelApp.set(null);
    this.installers.set([]);
  }

  createInvite(): void {
    const app = this.invitePanelApp();
    if (!app) return;
    this.isCreatingInvite.set(true);
    this.appInviteService
      .createInvite(app.id)
      .pipe(catchError(() => of(null)))
      .subscribe((invite) => {
        if (invite) {
          this.invites.update((list) => [invite, ...list]);
        }
        this.isCreatingInvite.set(false);
      });
  }

  copyClientId(clientId: string): void {
    navigator.clipboard.writeText(clientId).catch(() => {});
  }

  revokeInvite(invite: AppInvite): void {
    const app = this.invitePanelApp();
    if (!app) return;
    this.appInviteService
      .revokeInvite(app.id, invite.id)
      .pipe(catchError(() => of(null)))
      .subscribe((updated) => {
        if (updated) {
          this.invites.update((list) =>
            list.map((i) => (i.id === updated.id ? updated : i)),
          );
        }
      });
  }
}
